from smolagents import Agent, tool

@vex.policy
def no_bias_scoring(resume_text: str, scores: dict) -> bool:
    protected_terms = ['age', 'race', 'gender', 'disability']
    return not any(term in str(scores).lower() for term in protected_terms)

@tool
def score_resume(resume_text: str) -> dict:
    # Simulated scoring logic
    return {'fit_score': 0.85, 'skills_match': 'high'}

agent = Agent(tools=[score_resume])

with vex.verify([no_bias_scoring]):
    result = agent.run('Score this resume: [candidate resume text]')
    print(result)

